const e={topicId:"irregular-verbs",title:"Essential Irregular Verbs",introduction:"Some of the most frequently used Romanian verbs are irregular, meaning they do not follow the standard conjugation patterns. The good news is that there are only a handful you need to memorize at the A1 level, and you will use them so often that they quickly become second nature.",sections:[{id:"a-fi-to-be",title:"A fi (to be)",blocks:[{type:"rule",title:"The Most Important Verb",content:'"A fi" (to be) is the most fundamental verb in Romanian. It is completely irregular and must be memorized. You will use it to describe people, things, states, and identities.'},{type:"table",headers:["Person","Conjugation","English"],rows:[["eu","sunt","I am"],["tu","ești","you are"],["el/ea","este / e","he/she is"],["noi","suntem","we are"],["voi","sunteți","you all are"],["ei/ele","sunt","they are"]],caption:"A fi — present tense conjugation",colorCoded:!0},{type:"example",romanian:"Sunt din România.",english:"I am from Romania.",highlights:[{text:"Sunt",role:"verb"}]},{type:"example",romanian:"Ea este profesoară.",english:"She is a teacher.",highlights:[{text:"Ea",role:"subject"},{text:"este",role:"verb"}]},{type:"callout",variant:"info",content:'"Este" is often shortened to "e" in spoken Romanian: "El e acasă" (He is at home). Both forms are correct, but "e" is more casual.'}]},{id:"a-avea-to-have",title:"A avea (to have)",blocks:[{type:"table",headers:["Person","Conjugation","English"],rows:[["eu","am","I have"],["tu","ai","you have"],["el/ea","are","he/she has"],["noi","avem","we have"],["voi","aveți","you all have"],["ei/ele","au","they have"]],caption:"A avea — present tense conjugation",colorCoded:!0},{type:"example",romanian:"Am doi frați și o soră.",english:"I have two brothers and a sister.",highlights:[{text:"Am",role:"verb"},{text:"doi frați și o soră",role:"object"}]},{type:"example",romanian:"Ai un minut?",english:"Do you have a minute?",highlights:[{text:"Ai",role:"verb"},{text:"un minut",role:"object"}]},{type:"callout",variant:"tip",content:'"A avea" is also used as a helper verb to form the past tense (perfect compus): "Am mâncat" (I ate/I have eaten). You will learn this construction later, but recognizing "am/ai/a/am/ați/au" is useful even now.'}]},{id:"a-face-a-vrea",title:"A face (to do/make) & A vrea (to want)",blocks:[{type:"table",headers:["Person","a face (to do)","a vrea (to want)"],rows:[["eu","fac","vreau"],["tu","faci","vrei"],["el/ea","face","vrea"],["noi","facem","vrem"],["voi","faceți","vreți"],["ei/ele","fac","vor"]],caption:"A face and a vrea — present tense",colorCoded:!0},{type:"example",romanian:"Ce faci? Fac cumpărături.",english:"What are you doing? I am shopping.",highlights:[{text:"faci",role:"verb"},{text:"Fac",role:"verb"},{text:"cumpărături",role:"object"}]},{type:"example",romanian:"Vreau o apă, te rog.",english:"I want a water, please.",highlights:[{text:"Vreau",role:"verb"},{text:"o apă",role:"object"}]},{type:"comparison",left:{title:"A face (to do/make)",items:["Ce faci? (What are you doing?)","Fac prânzul. (I am making lunch.)",'Very common greeting: "Ce faci?" = "How are you?"']},right:{title:"A vrea (to want)",items:["Vreau să merg. (I want to go.)","Nu vreau. (I don't want to.)",'Used with "să" + subjunctive']}}]},{id:"a-putea-a-sti",title:"A putea (can) & A ști (to know)",blocks:[{type:"table",headers:["Person","a putea (can)","a ști (to know)"],rows:[["eu","pot","știu"],["tu","poți","știi"],["el/ea","poate","știe"],["noi","putem","știm"],["voi","puteți","știți"],["ei/ele","pot","știu"]],caption:"A putea and a ști — present tense",colorCoded:!0},{type:"example",romanian:"Pot să te ajut?",english:"Can I help you?",highlights:[{text:"Pot",role:"verb"}]},{type:"example",romanian:"Nu știu unde este gara.",english:"I don't know where the train station is.",highlights:[{text:"Nu",role:"negation"},{text:"știu",role:"verb"}]},{type:"callout",variant:"tip",content:'Both "a putea" and "a vrea" are followed by "să" + the subjunctive form of the next verb: "Pot să merg" (I can go), "Vreau să mănânc" (I want to eat). This "să + verb" construction replaces the infinitive in most modern Romanian speech.'}]}]};export{e as default};
